/**
 * fonts-cyrillic.js — Custom fonts embedded as base64 for jsPDF.
 * Contains:
 *   Roboto Regular/Bold — universal Cyrillic fallback
 *   Samurai (Kashima RUS) — for Samurai PDF preset
 *   Medieval — for Medieval PDF preset
 *   Cyberpunk — for Cyberpunk PDF preset
 *
 * Regenerate: run generate-fonts.py in /tools after adding new TTF/OTF files.
 */

// Roboto — universal Cyrillic base font (used when no preset font loaded)
window.__ROBOTO_REGULAR_B64 = "";
window.__ROBOTO_BOLD_B64 = "";

// Preset-specific fonts — loaded dynamically by the PDF module
window.__FONT_B64 = {
  samurai:  "",
  medieval: "",
  cyberpunk:"",
};
